# vault config: auto-unseal with a cloud KMS key
seal "awskms" {
  region     = "us-east-1"
  kms_key_id = "arn:aws:kms:us-east-1:111122223333:key/abc-123"
}

# Shamir key shares become recovery keys, used only for break-glass

# vault config: Integrated Storage (Raft)
storage "raft" {
  path    = "/vault/data"
  node_id = "vault-1"
  retry_join { leader_api_addr = "https://vault-2:8200" }
  retry_join { leader_api_addr = "https://vault-3:8200" }
}
cluster_addr = "https://vault-1:8201"
